<script setup lang="ts">
  import { ref, onMounted, computed, watch } from 'vue';
  import { number } from 'mathjs';

  const props = defineProps({
    process: {
      type: number,
      default: 0,
    },
  });

  // 基础配置
  const strokeWidth = 38.6;
  const progressPath = ref<SVGPathElement | null>(null);
  const pathLength = ref(0);
  const isAnimated = ref(false);
  const progress = ref(0);

  // 计算进度条样式
  const progressStyle = computed(() => ({
    '--path-length': pathLength.value,
    'stroke-dashoffset': pathLength.value * (1 - progress.value / 100),
  }));

  // 设置进度
  const setProgress = (percent: number, animate = true) => {
    progress.value = Math.max(0, Math.min(100, percent));
    isAnimated.value = animate;
  };

  // 初始化
  onMounted(() => {
    if (progressPath.value) {
      pathLength.value = progressPath.value.getTotalLength();
      setProgress(0, false); // 初始设置为0%，无动画

      // 延迟启用动画
      // setTimeout(() => {
      //   isAnimated.value = true;
      //   setProgress(75);
      // }, 100);
    }
  });

  watch(
    () => props.process,
    newVal => {
      setProgress(newVal || 0);
    },
  );

  // 如果需要暴露给模板的变量会自动暴露，无需return
  // 如果需要暴露给父组件使用，可以使用defineExpose
  defineExpose({
    setProgress,
  });
</script>

